    /**
     * Get all of INTF's bit fields.
     *
     * (read-write) Interrupt Force
     */
    inline void get_INTF(
        bool &HOST_CONN_DIS, bool &HOST_RESUME, bool &HOST_SOF,
        bool &TRANS_COMPLETE, bool &BUFF_STATUS, bool &ERROR_DATA_SEQ,
        bool &ERROR_RX_TIMEOUT, bool &ERROR_RX_OVERFLOW, bool &ERROR_BIT_STUFF,
        bool &ERROR_CRC, bool &STALL, bool &VBUS_DETECT, bool &BUS_RESET,
        bool &DEV_CONN_DIS, bool &DEV_SUSPEND, bool &DEV_RESUME_FROM_HOST,
        bool &SETUP_REQ, bool &DEV_SOF, bool &ABORT_DONE, bool &EP_STALL_NAK,
        bool &RX_SHORT_PACKET, bool &ENDPOINT_ERROR,
        bool &DEV_SM_WATCHDOG_FIRED, bool &EPX_STOPPED_ON_NAK) volatile
    {
        uint32_t curr = INTF;

        HOST_CONN_DIS = curr & 1u;
        HOST_RESUME = curr & (1u << 1u);
        HOST_SOF = curr & (1u << 2u);
        TRANS_COMPLETE = curr & (1u << 3u);
        BUFF_STATUS = curr & (1u << 4u);
        ERROR_DATA_SEQ = curr & (1u << 5u);
        ERROR_RX_TIMEOUT = curr & (1u << 6u);
        ERROR_RX_OVERFLOW = curr & (1u << 7u);
        ERROR_BIT_STUFF = curr & (1u << 8u);
        ERROR_CRC = curr & (1u << 9u);
        STALL = curr & (1u << 10u);
        VBUS_DETECT = curr & (1u << 11u);
        BUS_RESET = curr & (1u << 12u);
        DEV_CONN_DIS = curr & (1u << 13u);
        DEV_SUSPEND = curr & (1u << 14u);
        DEV_RESUME_FROM_HOST = curr & (1u << 15u);
        SETUP_REQ = curr & (1u << 16u);
        DEV_SOF = curr & (1u << 17u);
        ABORT_DONE = curr & (1u << 18u);
        EP_STALL_NAK = curr & (1u << 19u);
        RX_SHORT_PACKET = curr & (1u << 20u);
        ENDPOINT_ERROR = curr & (1u << 21u);
        DEV_SM_WATCHDOG_FIRED = curr & (1u << 22u);
        EPX_STOPPED_ON_NAK = curr & (1u << 23u);
    }

    /**
     * Set all of INTF's bit fields.
     *
     * (read-write) Interrupt Force
     */
    inline void set_INTF(bool HOST_CONN_DIS, bool HOST_RESUME, bool HOST_SOF,
                         bool TRANS_COMPLETE, bool BUFF_STATUS,
                         bool ERROR_DATA_SEQ, bool ERROR_RX_TIMEOUT,
                         bool ERROR_RX_OVERFLOW, bool ERROR_BIT_STUFF,
                         bool ERROR_CRC, bool STALL, bool VBUS_DETECT,
                         bool BUS_RESET, bool DEV_CONN_DIS, bool DEV_SUSPEND,
                         bool DEV_RESUME_FROM_HOST, bool SETUP_REQ,
                         bool DEV_SOF, bool ABORT_DONE, bool EP_STALL_NAK,
                         bool RX_SHORT_PACKET, bool ENDPOINT_ERROR,
                         bool DEV_SM_WATCHDOG_FIRED,
                         bool EPX_STOPPED_ON_NAK) volatile
    {
        uint32_t curr = INTF;

        curr &= ~(0b1u);
        curr |= (HOST_CONN_DIS & 0b1u);
        curr &= ~(0b1u << 1u);
        curr |= (HOST_RESUME & 0b1u) << 1u;
        curr &= ~(0b1u << 2u);
        curr |= (HOST_SOF & 0b1u) << 2u;
        curr &= ~(0b1u << 3u);
        curr |= (TRANS_COMPLETE & 0b1u) << 3u;
        curr &= ~(0b1u << 4u);
        curr |= (BUFF_STATUS & 0b1u) << 4u;
        curr &= ~(0b1u << 5u);
        curr |= (ERROR_DATA_SEQ & 0b1u) << 5u;
        curr &= ~(0b1u << 6u);
        curr |= (ERROR_RX_TIMEOUT & 0b1u) << 6u;
        curr &= ~(0b1u << 7u);
        curr |= (ERROR_RX_OVERFLOW & 0b1u) << 7u;
        curr &= ~(0b1u << 8u);
        curr |= (ERROR_BIT_STUFF & 0b1u) << 8u;
        curr &= ~(0b1u << 9u);
        curr |= (ERROR_CRC & 0b1u) << 9u;
        curr &= ~(0b1u << 10u);
        curr |= (STALL & 0b1u) << 10u;
        curr &= ~(0b1u << 11u);
        curr |= (VBUS_DETECT & 0b1u) << 11u;
        curr &= ~(0b1u << 12u);
        curr |= (BUS_RESET & 0b1u) << 12u;
        curr &= ~(0b1u << 13u);
        curr |= (DEV_CONN_DIS & 0b1u) << 13u;
        curr &= ~(0b1u << 14u);
        curr |= (DEV_SUSPEND & 0b1u) << 14u;
        curr &= ~(0b1u << 15u);
        curr |= (DEV_RESUME_FROM_HOST & 0b1u) << 15u;
        curr &= ~(0b1u << 16u);
        curr |= (SETUP_REQ & 0b1u) << 16u;
        curr &= ~(0b1u << 17u);
        curr |= (DEV_SOF & 0b1u) << 17u;
        curr &= ~(0b1u << 18u);
        curr |= (ABORT_DONE & 0b1u) << 18u;
        curr &= ~(0b1u << 19u);
        curr |= (EP_STALL_NAK & 0b1u) << 19u;
        curr &= ~(0b1u << 20u);
        curr |= (RX_SHORT_PACKET & 0b1u) << 20u;
        curr &= ~(0b1u << 21u);
        curr |= (ENDPOINT_ERROR & 0b1u) << 21u;
        curr &= ~(0b1u << 22u);
        curr |= (DEV_SM_WATCHDOG_FIRED & 0b1u) << 22u;
        curr &= ~(0b1u << 23u);
        curr |= (EPX_STOPPED_ON_NAK & 0b1u) << 23u;

        INTF = curr;
    }

